        </div>
    }

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
            @if (isSaving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="DiscardChanges" disabled="@isSaving">
            Discard Changes
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public UserProfile? Profile { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<UserProfile> OnSave { get; set; }

    private string displayName = "";
    private string email = "";
    private string avatarUrl = "";
    private string bio = "";
    private string? statusMessage;
    private bool isError;
    private bool isSaving;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !isSaving)
        {
            LoadFromProfile(Profile);
        }
    }

    private void LoadFromProfile(UserProfile profile)
    {
        displayName = profile.DisplayName;
        email = profile.Email;
        avatarUrl = profile.AvatarUrl;
        bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        statusMessage = null;
        try
        {
            var updated = new UserProfile(displayName, email, avatarUrl, bio);
            await OnSave.InvokeAsync(updated);
            statusMessage = "Profile saved successfully!";
            isError = false;
        }
        catch
        {
            statusMessage = "Failed to save profile. Please try again.";
            isError = true;
        }
        finally
        {
            isSaving = false;
        }
    }

    private void DiscardChanges()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
            statusMessage = null;
        }
    }
}
