@code {
    [Parameter, EditorRequired]
    public AppearanceSettings? Appearance { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string theme = "Light";
    private string fontSize = "Medium";
    private string language = "en";
    private bool compactMode;
    private string? statusMessage;
    private bool isSaving;

    protected override void OnParametersSet()
    {
        if (Appearance is not null && !isSaving)
        {
            theme = Appearance.Theme;
            fontSize = Appearance.FontSize;
            language = Appearance.Language;
            compactMode = Appearance.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(theme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "system" => "preview-system",
            _ => "preview-light"
        });
        classes.Add(fontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-small",
            "large" => "preview-font-large",
            _ => "preview-font-medium"
        });
        if (compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private static string GetLanguageName(string code) => code switch
    {
        "en" => "English",
        "es" => "Spanish",
        "fr" => "French",
        "de" => "German",
        "ja" => "Japanese",
        "zh" => "Chinese",
        "pt" => "Portuguese",
        _ => code
    };

    private async Task SaveAsync()
    {
        isSaving = true;
        statusMessage = null;
        try
        {
            var updated = new AppearanceSettings(theme, fontSize, language, compactMode);
            await OnSave.InvokeAsync(updated);
            statusMessage = "Appearance settings saved!";
        }
        finally
        {
            isSaving = false;
        }
    }
}
