@namespace sv_dec873932ea546d7ba0ddef6df0d0446.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionSelected.InvokeAsync(section)">
                    <span class="section-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired]
    public string ActiveSection { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<string> OnSectionSelected { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_dec873932ea546d7ba0ddef6df0d0446.Components.Pages.Settings
@using sv_dec873932ea546d7ba0ddef6df0d0446.Models

<div class="profile-section">
    <h4>Profile Settings</h4>
    <p class="text-muted">Manage your personal information.</p>
    <hr />

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="email" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @bind="bio"></textarea>
            </div>
        </div>
        <div class="col-md-4">
            <div class="avatar-preview-area text-center">
                <label class="form-label fw-semibold d-block">Avatar Preview</label>
                <div class="avatar-frame mb-2">
                    @if (!string.IsNullOrWhiteSpace(avatarUrl))
                    {
                        <img src="@avatarUrl" alt="Avatar" class="avatar-img" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">👤</div>
                    }
                </div>
                <small class="text-muted text-break">@avatarUrl</small>
            </div>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show mt-3" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
            @if (isSaving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="DiscardChanges" disabled="@isSaving">
            Discard Changes
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public UserProfile? Profile { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<UserProfile> OnSave { get; set; }

    private string displayName = "";
    private string email = "";
    private string avatarUrl = "";
    private string bio = "";
    private string? statusMessage;
    private bool isError;
    private bool isSaving;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !isSaving)
        {
            LoadFromProfile(Profile);
        }
    }

    private void LoadFromProfile(UserProfile profile)
    {
        displayName = profile.DisplayName;
        email = profile.Email;
        avatarUrl = profile.AvatarUrl;
        bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        statusMessage = null;
        try
        {
            var updated = new UserProfile(displayName, email, avatarUrl, bio);
            await OnSave.InvokeAsync(updated);
            statusMessage = "Profile saved successfully!";
            isError = false;
        }
        catch
        {
            statusMessage = "Failed to save profile. Please try again.";
            isError = true;
        }
        finally
        {
            isSaving = false;
        }
    }

    private void DiscardChanges()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
            statusMessage = null;
        }
    }
}

