@namespace sv_dec873932ea546d7ba0ddef6df0d0446.Components.Pages.Settings
@using sv_dec873932ea546d7ba0ddef6df0d0446.Models

<div class="notifications-section">
    <h4>Notification Preferences</h4>
    <p class="text-muted">Choose how you want to be notified.</p>
    <hr />

    <div class="mb-4">
        <h6 class="fw-semibold">Notification Channels</h6>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    @if (AvailableChannels.Count > 0)
    {
        <div class="mb-4">
            <h6 class="fw-semibold">Muted Channels</h6>
            <p class="text-muted small">Select channels you want to mute.</p>

            <div class="channel-list">
                @foreach (var channel in AvailableChannels)
                {
                    var isMuted = mutedChannels.Contains(channel);
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox"
                               id="@($"channel-{channel}")"
                               checked="@isMuted"
                               @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"channel-{channel}")">@channel</label>
                    </div>
                }
            </div>
        </div>
    }

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
        @if (isSaving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public NotificationPrefs? Prefs { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<NotificationPrefs> OnSave { get; set; }

    [Parameter]
    public List<string> AvailableChannels { get; set; } = ["general", "updates", "marketing", "alerts", "support"];

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private string? statusMessage;
    private bool isSaving;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !isSaving)
        {
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            mutedChannels = new HashSet<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool isMuted)
    {
        if (isMuted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        statusMessage = null;
        try
        {
            var updated = new NotificationPrefs(
                emailNotifications, pushNotifications, weeklyDigest,
                mutedChannels.ToList());
            await OnSave.InvokeAsync(updated);
            statusMessage = "Preferences saved successfully!";
        }
        finally
        {
            isSaving = false;
        }
    }
}

