+                <input type="password" class="form-control" @bind="currentPassword" />
+            </div>
+            <div class="mb-3">
+                <label class="form-label fw-semibold">New Password</label>
+                <input type="password" class="form-control" @bind="newPassword" />
+            </div>
+            <div class="mb-3">
+                <label class="form-label fw-semibold">Confirm New Password</label>
+                <input type="password" class="form-control" @bind="confirmPassword" />
+            </div>
+
+            @if (!string.IsNullOrEmpty(errorMessage))
+            {
+                <div class="alert alert-danger py-2" role="alert">@errorMessage</div>
+            }
+            @if (!string.IsNullOrEmpty(successMessage))
+            {
+                <div class="alert alert-success py-2" role="alert">@successMessage</div>
+            }
+
+            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@isUpdating">
+                @if (isUpdating)
+                {
+                    <span class="spinner-border spinner-border-sm me-1"></span>
+                }
+                Update Password
+            </button>
+        </div>
+    }
+</div>
+
+@code {
+    [Parameter, EditorRequired]
+    public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }
+
+    private bool isExpanded;
+    private string currentPassword = "";
+    private string newPassword = "";
+    private string confirmPassword = "";
+    private string? errorMessage;
+    private string? successMessage;
+    private bool isUpdating;
+
+    private async Task UpdatePasswordAsync()
+    {
+        errorMessage = null;
+        successMessage = null;
+
+        if (string.IsNullOrWhiteSpace(currentPassword) ||
+            string.IsNullOrWhiteSpace(newPassword) ||
+            string.IsNullOrWhiteSpace(confirmPassword))
+        {
+            errorMessage = "All fields are required.";
+            return;
+        }
+
+        if (newPassword != confirmPassword)
+        {
+            errorMessage = "New password and confirmation do not match.";
+            return;
+        }
+
+        if (newPassword.Length < 8)
+        {
+            errorMessage = "New password must be at least 8 characters.";
+            return;
+        }
+
+        isUpdating = true;
+        try
+        {
+            await OnChangePassword.InvokeAsync((currentPassword, newPassword));
+            successMessage = "Password updated successfully!";
+            currentPassword = "";
+            newPassword = "";
+            confirmPassword = "";
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to update password: {ex.Message}";
+        }
+        finally
+        {
+            isUpdating = false;
+        }
+    }
+}
+

