@namespace sv_dec873932ea546d7ba0ddef6df0d0446.Components.Pages.Settings

@if (IsVisible)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal d-block fade show" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session?</p>
                    @if (!string.IsNullOrEmpty(DeviceName))
                    {
                        <p class="mb-0">
                            <strong>Device:</strong> @DeviceName<br />
                            <strong>Location:</strong> @Location
                        </p>
                    }
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool IsVisible { get; set; }
    [Parameter] public string? DeviceName { get; set; }
    [Parameter] public string? Location { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@namespace sv_dec873932ea546d7ba0ddef6df0d0446.Components.Pages.Settings
@using sv_dec873932ea546d7ba0ddef6df0d0446.Models

<div class="mb-4">
    <h6 class="fw-semibold">Active Sessions</h6>
    @if (Sessions is null || Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover align-middle">
                <thead class="table-light">
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        var isCurrent = session.Id == CurrentSessionId;
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="badge bg-success ms-2">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("MMM dd, yyyy h:mm tt")</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => RequestRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

<RevokeSessionDialog IsVisible="@showConfirmDialog"
                     DeviceName="@sessionToRevoke?.Device"
                     Location="@sessionToRevoke?.Location"
                     OnConfirm="ConfirmRevoke"
                     OnCancel="CancelRevoke" />

@code {
    [Parameter, EditorRequired]
    public List<ActiveSession>? Sessions { get; set; }

    [Parameter]
    public string? CurrentSessionId { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnRevoke { get; set; }

    private bool showConfirmDialog;
    private ActiveSession? sessionToRevoke;

    private void RequestRevoke(ActiveSession session)
    {
        sessionToRevoke = session;
        showConfirmDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (sessionToRevoke is not null)
        {
            await OnRevoke.InvokeAsync(sessionToRevoke.Id);
        }
        showConfirmDialog = false;
        sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        showConfirmDialog = false;
        sessionToRevoke = null;
    }
}

