@namespace sv_dec873932ea546d7ba0ddef6df0d0446.Components.Pages.Settings
@using sv_dec873932ea546d7ba0ddef6df0d0446.Models

<div class="security-section">
    <h4>Security Settings</h4>
    <p class="text-muted">Manage your account security.</p>
    <hr />

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <div class="mb-4">
        <h6 class="fw-semibold">Two-Factor Authentication</h6>
        <div class="d-flex align-items-center gap-3">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@twoFactorEnabled" disabled />
                <label class="form-check-label" for="twoFactor">
                    Two-Factor Authentication
                </label>
            </div>
            <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(twoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        @if (Settings?.LastPasswordChange is not null)
        {
            <small class="text-muted d-block mt-2">
                Last password change: @Settings.LastPasswordChange.Value.ToString("MMM dd, yyyy")
            </small>
        }
    </div>

    <ActiveSessionsTable Sessions="@Settings?.Sessions?.ToList()"
                         CurrentSessionId="@currentSessionId"
                         OnRevoke="HandleRevokeSession" />
</div>

@code {
    [Parameter, EditorRequired]
    public SecuritySettings? Settings { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnRevokeSession { get; set; }

    private bool twoFactorEnabled;
    private string? currentSessionId;

    protected override void OnParametersSet()
    {
        if (Settings is not null)
        {
            twoFactorEnabled = Settings.TwoFactorEnabled;
            // Assume first session is the current one
            currentSessionId = Settings.Sessions?.FirstOrDefault()?.Id;
        }
    }

    private async Task HandleChangePassword((string CurrentPassword, string NewPassword) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
    }
}

