@namespace sv_dec873932ea546d7ba0ddef6df0d0446.Components.Pages.Settings
@using sv_dec873932ea546d7ba0ddef6df0d0446.Models

<div class="appearance-section">
    <h4>Appearance Settings</h4>
    <p class="text-muted">Customize how the application looks.</p>
    <hr />

    <div class="row">
        <div class="col-md-7">
            <div class="mb-4">
                <h6 class="fw-semibold">Theme</h6>
                @foreach (var t in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{t}")" value="@t"
                               checked="@(theme == t)"
                               @onchange="() => theme = t" />
                        <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6 class="fw-semibold">Font Size</h6>
                @foreach (var fs in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{fs}")" value="@fs"
                               checked="@(fontSize == fs)"
                               @onchange="() => fontSize = fs" />
                        <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6 class="fw-semibold">Language</h6>
                <select class="form-select" style="max-width: 300px;" @bind="language">
                    <option value="en">English</option>
                    <option value="es">Spanish</option>
                    <option value="fr">French</option>
                    <option value="de">German</option>
                    <option value="ja">Japanese</option>
                    <option value="zh">Chinese</option>
                    <option value="pt">Portuguese</option>
                </select>
            </div>

            <div class="mb-4">
                <h6 class="fw-semibold">Compact Mode</h6>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="compactMode" />
                    <label class="form-check-label" for="compactMode">
                        Enable compact mode for denser layouts
                    </label>
                </div>
            </div>

            @if (!string.IsNullOrEmpty(statusMessage))
            {
                <div class="alert alert-success alert-dismissible fade show" role="alert">
                    @statusMessage
                    <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
                </div>
            }

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
                @if (isSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-5">
            <h6 class="fw-semibold">Live Preview</h6>
            <div class="preview-area @GetPreviewClasses()">
                <div class="preview-header">
                    <strong>Sample Header</strong>
                </div>
                <div class="preview-body">
                    <p>This is a preview of your selected settings.</p>
                    <ul>
                        <li>Theme: @theme</li>
                        <li>Font Size: @fontSize</li>
                        <li>Language: @GetLanguageName(language)</li>
                        <li>Compact: @(compactMode ? "On" : "Off")</li>
                    </ul>
                    <button class="btn btn-sm btn-primary">Sample Button</button>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public AppearanceSettings? Appearance { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string theme = "Light";
    private string fontSize = "Medium";
    private string language = "en";
    private bool compactMode;
    private string? statusMessage;
    private bool isSaving;

    protected override void OnParametersSet()
    {
        if (Appearance is not null && !isSaving)
        {
            theme = Appearance.Theme;
            fontSize = Appearance.FontSize;
            language = Appearance.Language;
            compactMode = Appearance.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(theme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "system" => "preview-system",
            _ => "preview-light"
        });
        classes.Add(fontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-small",
            "large" => "preview-font-large",
            _ => "preview-font-medium"
        });
        if (compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private static string GetLanguageName(string code) => code switch
    {
        "en" => "English",
        "es" => "Spanish",
        "fr" => "French",
        "de" => "German",
        "ja" => "Japanese",
        "zh" => "Chinese",
        "pt" => "Portuguese",
        _ => code
    };

    private async Task SaveAsync()
    {
        isSaving = true;
        statusMessage = null;
        try
        {
            var updated = new AppearanceSettings(theme, fontSize, language, compactMode);
            await OnSave.InvokeAsync(updated);
            statusMessage = "Appearance settings saved!";
        }
        finally
        {
            isSaving = false;
        }
    }
}

.appearance-section {
    padding: 0.5rem 0;
}

.preview-area {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.3s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
}

.preview-body {
    padding: 1rem;
}

/* Theme variants */
.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-light .preview-header {
    background: #f8f9fa;
    border-color: #dee2e6;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-dark .preview-header {
    background: #2d2d3f;
    border-color: #444;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

.preview-system .preview-header {
    background: #e9ecef;
}

/* Font size variants */
.preview-font-small {
    font-size: 0.8rem;
}

.preview-font-medium {
