arguments.file_text:
@page "/settings"
@namespace sv_dec873932ea546d7ba0ddef6df0d0446.Components.Pages.Settings
@rendermode InteractiveServer
@using sv_dec873932ea546d7ba0ddef6df0d0446.Models
@using sv_dec873932ea546d7ba0ddef6df0d0446.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@activeSection"
                     OnSectionSelected="SelectSection" />

    <div class="settings-content">
        @if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="@profile"
                                    OnSave="SaveProfileAsync" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@notificationPrefs"
                                          OnSave="SaveNotificationsAsync" />
                    break;
                case "Security":
                    <SecuritySection Settings="@securitySettings"
                                     OnChangePassword="ChangePasswordAsync"
                                     OnRevokeSession="RevokeSessionAsync" />
                    break;
                case "Appearance":
                    <AppearanceSection Appearance="@appearanceSettings"
                                       OnSave="SaveAppearanceAsync" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string activeSection = "Profile";
    private bool isLoading;

    private UserProfile? profile;
    private NotificationPrefs? notificationPrefs;
    private SecuritySettings? securitySettings;
    private AppearanceSettings? appearanceSettings;

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionDataAsync();
    }

    private async Task SelectSection(string section)
    {
        activeSection = section;
        await LoadSectionDataAsync();
    }

    private async Task LoadSectionDataAsync()
    {
        isLoading = true;
        try
        {
            switch (activeSection)
            {
                case "Profile" when profile is null:
                    profile = await SettingsService.GetProfileAsync();
                    break;
                case "Notifications" when notificationPrefs is null:
                    notificationPrefs = await SettingsService.GetNotificationPrefsAsync();
                    break;
                case "Security" when securitySettings is null:
                    securitySettings = await SettingsService.GetSecuritySettingsAsync();
                    break;
                case "Appearance" when appearanceSettings is null:
                    appearanceSettings = await SettingsService.GetAppearanceAsync();
                    break;
            }
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SaveProfileAsync(UserProfile updated)
    {
        await SettingsService.SaveProfileAsync(updated);
        profile = updated;
    }

    private async Task SaveNotificationsAsync(NotificationPrefs updated)
    {
        await SettingsService.SaveNotificationPrefsAsync(updated);
        notificationPrefs = updated;
    }

    private async Task ChangePasswordAsync((string CurrentPassword, string NewPassword) args)
    {
        await SettingsService.ChangePasswordAsync(args.CurrentPassword, args.NewPassword);
        // Refresh security settings to update last password change date
        securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearanceAsync(AppearanceSettings updated)
    {
        await SettingsService.SaveAppearanceAsync(updated);
        appearanceSettings = updated;
    }
}

.settings-layout {
    display: flex;
    min-height: calc(100vh - 60px);
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    background: #fff;
    margin: 1rem;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

